 Gnome の設定 # Wayland の無効化 # /etc/gdm/custom.conf を下記のように編集します．
- #WaylandEnable=false + WaylandEnable=false + DefaultSession=gnome-xorg.desktop /usr/lib/gdm-disable-wayland を root 権限で実行してもOKです．
sudo /usr/lib/gdm-disable-wayland アラート音を消す # dconf write /org/gnome/desktop/sound/event-sounds &#34;false&#34;

 Systems # Linux v5.8.13 x86-64 Read # File: arch/x86/kernel/process_64.c long do_arch_prctl_64(struct task_struct *task, int option, unsigned long arg2) { int ret = 0; switch (option) { ... case ARCH_GET_FS: { unsigned long base = x86_fsbase_read_task(task); ret = put_user(base, (unsigned long __user *)arg2); break; } case ARCH_GET_GS: { unsigned long base = x86_gsbase_read_task(task); ret = put_user(base, (unsigned long __user *)arg2); break; } ... default: ret = -EINVAL; break; } return ret; } File: arch/x86/kernel/process_64.c static unsigned long x86_fsgsbase_read_task(struct task_struct *task, unsigned short selector) { unsigned short idx = selector &gt;&gt; 3; unsigned long base; if (likely((selector &amp; SEGMENT_TI_MASK) == 0)) { if (unlikely(idx &gt;= GDT_ENTRIES)) return 0; /* * There are no user segments in the GDT with nonzero bases * other than the TLS segments. */ if (idx &lt; GDT_ENTRY_TLS_MIN || idx &gt; GDT_ENTRY_TLS_MAX) return 0; idx -= GDT_ENTRY_TLS_MIN; base = get_desc_base(&amp;task-&gt;thread.tls_array[idx]); } else { #ifdef CONFIG_MODIFY_LDT_SYSCALL struct ldt_struct *ldt; /* * If performance here mattered, we could protect the LDT * with RCU. This is a slow path, though, so we can just * take the mutex. */ mutex_lock(&amp;task-&gt;mm-&gt;context.lock); ldt = task-&gt;mm-&gt;context.ldt; if (unlikely(!ldt || idx &gt;= ldt-&gt;nr_entries)) base = 0; else base = get_desc_base(ldt-&gt;entries + idx); mutex_unlock(&amp;task-&gt;mm-&gt;context.lock); #else base = 0; #endif } return base; } unsigned long x86_fsbase_read_task(struct task_struct *task) { unsigned long fsbase; if (task == current) fsbase = x86_fsbase_read_cpu(); else if (task-&gt;thread.fsindex == 0) fsbase = task-&gt;thread.fsbase; else fsbase = x86_fsgsbase_read_task(task, task-&gt;thread.fsindex); return fsbase; } unsigned long x86_gsbase_read_task(struct task_struct *task) { unsigned long gsbase; if (task == current) gsbase = x86_gsbase_read_cpu_inactive(); else if (task-&gt;thread.gsindex == 0) gsbase = task-&gt;thread.gsbase; else gsbase = x86_fsgsbase_read_task(task, task-&gt;thread.gsindex); return gsbase; } File: arch/x86/include/asm/fsgsbase.h #include &lt;asm/msr-index.h&gt; /* * Read/write a task&#39;s FSBASE or GSBASE. This returns the value that * the FS/GS base would have (if the task were to be resumed). These * work on the current task or on a non-running (typically stopped * ptrace child) task. */ extern unsigned long x86_fsbase_read_task(struct task_struct *task); extern unsigned long x86_gsbase_read_task(struct task_struct *task); /* Helper functions for reading/writing FS/GS base */ static inline unsigned long x86_fsbase_read_cpu(void) { unsigned long fsbase; rdmsrl(MSR_FS_BASE, fsbase); return fsbase; } static inline unsigned long x86_gsbase_read_cpu_inactive(void) { unsigned long gsbase; rdmsrl(MSR_KERNEL_GS_BASE, gsbase); return gsbase; } Write # File: arch/x86/kernel/process_64.c
long do_arch_prctl_64(struct task_struct *task, int option, unsigned long arg2) { int ret = 0; switch (option) { case ARCH_SET_GS: { if (unlikely(arg2 &gt;= TASK_SIZE_MAX)) return -EPERM; preempt_disable(); /* * ARCH_SET_GS has always overwritten the index * and the base. Zero is the most sensible value * to put in the index, and is the only value that * makes any sense if FSGSBASE is unavailable. */ if (task == current) { loadseg(GS, 0); x86_gsbase_write_cpu_inactive(arg2); /* * On non-FSGSBASE systems, save_base_legacy() expects * that we also fill in thread.gsbase. */ task-&gt;thread.gsbase = arg2; } else { task-&gt;thread.gsindex = 0; x86_gsbase_write_task(task, arg2); } preempt_enable(); break; } case ARCH_SET_FS: { /* * Not strictly needed for %fs, but do it for symmetry * with %gs */ if (unlikely(arg2 &gt;= TASK_SIZE_MAX)) return -EPERM; preempt_disable(); /* * Set the selector to 0 for the same reason * as %gs above. */ if (task == current) { loadseg(FS, 0); x86_fsbase_write_cpu(arg2); /* * On non-FSGSBASE systems, save_base_legacy() expects * that we also fill in thread.fsbase. */ task-&gt;thread.fsbase = arg2; } else { task-&gt;thread.fsindex = 0; x86_fsbase_write_task(task, arg2); } preempt_enable(); break; } ... default: ret = -EINVAL; break; } return ret; } File: arch/x86/include/asm/fsgsbase.h
#include &lt;asm/msr-index.h&gt; /* * Read/write a task&#39;s FSBASE or GSBASE. This returns the value that * the FS/GS base would have (if the task were to be resumed). These * work on the current task or on a non-running (typically stopped * ptrace child) task. */ extern void x86_fsbase_write_task(struct task_struct *task, unsigned long fsbase); extern void x86_gsbase_write_task(struct task_struct *task, unsigned long gsbase); /* Helper functions for reading/writing FS/GS base */ static inline void x86_fsbase_write_cpu(unsigned long fsbase) { wrmsrl(MSR_FS_BASE, fsbase); } static inline void x86_gsbase_write_cpu_inactive(unsigned long gsbase) { wrmsrl(MSR_KERNEL_GS_BASE, gsbase); } File: arch/x86/kernel/process_64.c
void x86_fsbase_write_task(struct task_struct *task, unsigned long fsbase) { WARN_ON_ONCE(task == current); task-&gt;thread.fsbase = fsbase; } void x86_gsbase_write_task(struct task_struct *task, unsigned long gsbase) { WARN_ON_ONCE(task == current); task-&gt;thread.gsbase = gsbase; }

 Version # Source code: https://sourceware.org/git/binutils-gdb.git GDB v13.0 Data Structures # File: gdb/symtab.h
struct symbol : public general_symbol_info, public allocate_on_obstack { symbol () /* Class-initialization of bitfields is only allowed in C++20. */ : m_domain (UNDEF_DOMAIN), m_aclass_index (0), m_is_objfile_owned (1), m_is_argument (0), m_is_inlined (0), maybe_copied (0), subclass (SYMBOL_NONE), m_artificial (false) { /* We can&#39;t use an initializer list for members of a base class, and general_symbol_info needs to stay a POD type. */ m_name = nullptr; m_value.ivalue = 0; language_specific.obstack = nullptr; m_language = language_unknown; ada_mangled = 0; m_section = -1; /* GCC 4.8.5 (on CentOS 7) does not correctly compile class- initialization of unions, so we initialize it manually here. */ owner.symtab = nullptr; } ... /* Return the symtab of this symbol. It is an error to call this if is_objfile_owned is false, which only happens for architecture-provided types. */ struct symtab *symtab () const; /* Set the symtab of this symbol to SYMTAB. It is an error to call this if is_objfile_owned is false, which only happens for architecture-provided types. */ void set_symtab (struct symtab *symtab); ... union { /* The symbol table containing this symbol. This is the file associated with LINE. It can be NULL during symbols read-in but it is never NULL during normal operation. */ struct symtab *symtab; /* For types defined by the architecture. */ struct gdbarch *arch; } owner; /* Domain code. */ ENUM_BITFIELD(domain_enum) m_domain : SYMBOL_DOMAIN_BITS; /* Address class. This holds an index into the &#39;symbol_impls&#39; table. The actual enum address_class value is stored there, alongside any per-class ops vectors. */ unsigned int m_aclass_index : SYMBOL_ACLASS_BITS; /* If non-zero then symbol is objfile-owned, use owner.symtab. Otherwise symbol is arch-owned, use owner.arch. */ unsigned int m_is_objfile_owned : 1; ... }; /* Each source file or header is represented by a struct symtab. The name &#34;symtab&#34; is historical, another name for it is &#34;filetab&#34;. These objects are chained through the `next&#39; field. */ struct symtab { struct compunit_symtab *compunit () const { return m_compunit; } void set_compunit (struct compunit_symtab *compunit) { m_compunit = compunit; } struct linetable *linetable () const { return m_linetable; } void set_linetable (struct linetable *linetable) { m_linetable = linetable; } enum language language () const { return m_language; } void set_language (enum language language) { m_language = language; } /* Unordered chain of all filetabs in the compunit, with the exception that the &#34;main&#34; source file is the first entry in the list. */ struct symtab *next; /* Backlink to containing compunit symtab. */ struct compunit_symtab *m_compunit; /* Table mapping core addresses to line numbers for this file. Can be NULL if none. Never shared between different symtabs. */ struct linetable *m_linetable; /* Name of this source file. This pointer is never NULL. */ const char *filename; /* Language of this source file. */ enum language m_language; /* Full name of file as found by searching the source path. NULL if not yet known. */ char *fullname; }; File: gdb/symtab.c
/* Check for a symtab of a specific name by searching some symtabs. This is a helper function for callbacks of iterate_over_symtabs. If NAME is not absolute, then REAL_PATH is NULL If NAME is absolute, then REAL_PATH is the gdb_realpath form of NAME. The return value, NAME, REAL_PATH and CALLBACK are identical to the `map_symtabs_matching_filename&#39; method of quick_symbol_functions. FIRST and AFTER_LAST indicate the range of compunit symtabs to search. Each symtab within the specified compunit symtab is also searched. AFTER_LAST is one past the last compunit symtab to search; NULL means to search until the end of the list. */ bool iterate_over_some_symtabs (const char *name, const char *real_path, struct compunit_symtab *first, struct compunit_symtab *after_last, gdb::function_view&lt;bool (symtab *)&gt; callback) { struct compunit_symtab *cust; const char* base_name = lbasename (name); for (cust = first; cust != NULL &amp;&amp; cust != after_last; cust = cust-&gt;next) { for (symtab *s : cust-&gt;filetabs ()) { if (compare_filenames_for_search (s-&gt;filename, name)) { if (callback (s)) return true; continue; } /* Before we invoke realpath, which can get expensive when many files are involved, do a quick comparison of the basenames. */ if (! basenames_may_differ &amp;&amp; FILENAME_CMP (base_name, lbasename (s-&gt;filename)) != 0) continue; if (compare_filenames_for_search (symtab_to_fullname (s), name)) { if (callback (s)) return true; continue; } /* If the user gave us an absolute path, try to find the file in this symtab and use its absolute path. */ if (real_path != NULL) { const char *fullname = symtab_to_fullname (s); gdb_assert (IS_ABSOLUTE_PATH (real_path)); gdb_assert (IS_ABSOLUTE_PATH (name)); gdb::unique_xmalloc_ptr&lt;char&gt; fullname_real_path = gdb_realpath (fullname); fullname = fullname_real_path.get (); if (FILENAME_CMP (real_path, fullname) == 0) { if (callback (s)) return true; continue; } } } } return false; } /* Check for a symtab of a specific name; first in symtabs, then in psymtabs. *If* there is no &#39;/&#39; in the name, a match after a &#39;/&#39; in the symtab filename will also work. Calls CALLBACK with each symtab that is found. If CALLBACK returns true, the search stops. */ void iterate_over_symtabs (const char *name, gdb::function_view&lt;bool (symtab *)&gt; callback) { gdb::unique_xmalloc_ptr&lt;char&gt; real_path; /* Here we are interested in canonicalizing an absolute path, not absolutizing a relative path. */ if (IS_ABSOLUTE_PATH (name)) { real_path = gdb_realpath (name); gdb_assert (IS_ABSOLUTE_PATH (real_path.get ())); } for (objfile *objfile : current_program_space-&gt;objfiles ()) { if (iterate_over_some_symtabs (name, real_path.get (), objfile-&gt;compunit_symtabs, NULL, callback)) return; } /* Same search rules as above apply here, but now we look thru the psymtabs. */ for (objfile *objfile : current_program_space-&gt;objfiles ()) { if (objfile-&gt;map_symtabs_matching_filename (name, real_path.get (), callback)) return; } } /* A wrapper for iterate_over_symtabs that returns the first matching symtab, or NULL. */ struct symtab * lookup_symtab (const char *name) { struct symtab *result = NULL; iterate_over_symtabs (name, [&amp;] (symtab *symtab) { result = symtab; return true; }); return result; }

 Segfault # プロセスリカバリの実験中にエラーが発生し segfault at 0 ip [useraddr] sp [useraddr] error 6 のようなログが得られたのでどこでエラーが起きているか確認したときのメモ． エラーログは arch/x86/mm/fault.c の show_signal_msg() で出力されていた．
/* * Print out info about fatal segfaults, if the show_unhandled_signals * sysctl is set: */ static inline void show_signal_msg(struct pt_regs *regs, unsigned long error_code, unsigned long address, struct task_struct *tsk) { const char *loglvl = task_pid_nr(tsk) &gt; 1 ? KERN_INFO : KERN_EMERG; if (!unhandled_signal(tsk, SIGSEGV)) return; if (!printk_ratelimit()) return; printk(&#34;%s%s[%d]: segfault at %lx ip %px sp %px error %lx&#34;, loglvl, tsk-&gt;comm, task_pid_nr(tsk), address, (void *)regs-&gt;ip, (void *)regs-&gt;sp, error_code); print_vma_addr(KERN_CONT &#34; in &#34;, regs-&gt;ip); printk(KERN_CONT &#34;\n&#34;); show_opcodes(regs, loglvl); } show_signal_msg() がどこで呼び出されているかたどっていくと bad_area_nosemaphore() か __bad_area() のどちらかで呼ばれていることがわかった． それぞれの呼び出しは下記のようになっていた．
--&gt; bad_area_nosemaphore() --&gt; __bad_area_nosemaphore() --&gt; show_signal_msg() asm_exc_page_fault() --&gt; handle_page_fault() --&gt; do_user_addr_fault() --&gt; bad_area() //--&gt; bad_area_access_error() --&gt; __bad_area() --&gt; __bad_area_nosemaphore() --&gt; show_signal_msg()
